output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT DISTINCT ?group WHERE {
  ?ceremony wdt:P139 wd:Q41254 ; wdt:P585 ?date .
  FILTER(SUBSTR(STR(?date) , 1 , 4) >= "2000" && SUBSTR(STR(?date) , 1 , 4) <= "2009")
  ?ceremony wdt:P175 ?group .
  ?group wdt:P31 wd:Q6526 .
  FILTER NOT EXISTS {
    ?group wdt:P31 wd:Q596
  }
}

